SELECT a.id, a.title, a.summary, a.cover, a.view_count, a.like_count, a.status, a.user_id AS author_id, u.nickname AS author_nickname, u.avatar AS author_avatar, a.category_id, c.name AS category_name, a.create_time FROM article a LEFT JOIN user u ON a.user_id = u.id LEFT JOIN category c ON a.category_id = c.id WHERE 1=1
AND (a.title LIKE CONCAT('%', #{keyword}, '%') OR a.summary LIKE CONCAT('%', #{keyword}, '%'))
